import java.util.*;

public class RestUrlValidator {

    public boolean isValidResourceUrl(String url) {
        // REST convention: lowercase, plural nouns, no verbs in URL
        // Valid: /users, /users/1, /users/1/orders
        // Invalid: /getUsers, /createUser, /deleteUser/1
        // TODO: Return false if URL contains verb prefixes: get, create, delete, update, fetch, retrieve
        // Return true otherwise
        return false;
    }

    public String categorize(String method, String url) {
        // TODO: Given HTTP method and URL, describe what REST operation it represents
        // GET /users -> "List all users"
        // GET /users/{id} -> "Get user by ID"
        // POST /users -> "Create new user"
        // PUT /users/{id} -> "Update user by ID"
        // DELETE /users/{id} -> "Delete user by ID"
        // Pattern: if url ends with a path variable like /{id} or /\d+
        return "Unknown operation";
    }
}

public class Main {
    public static void main(String[] args) {
        RestUrlValidator validator = new RestUrlValidator();

        // Test URL validation
        String[] urls = {"/users", "/users/1", "/getUsers", "/createUser", "/products/5/reviews"};
        System.out.println("URL Validation:");
        for (String url : urls) {
            System.out.println("  " + url + " -> " + (validator.isValidResourceUrl(url) ? "VALID" : "INVALID"));
        }

        // Test operation categorization
        System.out.println("\nREST Operations:");
        System.out.println("  " + validator.categorize("GET", "/users"));
        System.out.println("  " + validator.categorize("GET", "/users/1"));
        System.out.println("  " + validator.categorize("POST", "/users"));
        System.out.println("  " + validator.categorize("PUT", "/users/1"));
        System.out.println("  " + validator.categorize("DELETE", "/users/1"));
    }
}

public class HttpResponse {
