import java.util.*;

public class Link {
    private String rel;
    private String href;
    private String method;

    public Link(String rel, String href, String method) {
        this.rel = rel; this.href = href; this.method = method;
    }

    @Override
    public String toString() { return "Link{rel='" + rel + "', href='" + href + "', method='" + method + "'}"; }
}

public class UserResponse {
    private int id;
    private String name;
    private String email;
    private List<Link> links = new ArrayList<>();

    public UserResponse(int id, String name, String email) {
        this.id = id; this.name = name; this.email = email;
    }

    public void addLink(Link link) { links.add(link); }
    public List<Link> getLinks() { return links; }

    @Override
    public String toString() {
        return "User{id=" + id + ", name='" + name + "', email='" + email + "'}";
    }
}

public class UserController {
    public UserResponse getUser(int id) {
        UserResponse user = new UserResponse(id, "Alice", "alice@example.com");
        // TODO: Add self link, update link, delete link, and 'users' collection link
        return user;
    }
}

public class Main {
    public static void main(String[] args) {
        UserController controller = new UserController();
        UserResponse response = controller.getUser(1);
        System.out.println(response);
        System.out.println("Links:");
        response.getLinks().forEach(l -> System.out.println("  " + l));
    }
}

